const SME2_MINMAX2_MASK: u32 = 0xFF30_FEC0; // pins [31:24]=0xC1 + [21]=1 + [20]=0 + [15:9]=1010000 + [7:6]=00; size/Zm[19:16]/[8]/[5]/Zd/[0] vary
