            let four_index = if (word >> 14) & 1 == 1 {
                Some((false, ((word >> 15) & 0b11) as u8))
            } else if (word >> 15) & 1 == 1 {
                Some((true, ((word >> 16) & 1) as u8))
            } else {
                None
            };
