                let rn = Arm64GeneralPurposeRegister::from_operand_bits_sp(reg_field(word, 5));
                let rm = Arm64GeneralPurposeRegister::from_operand_bits(reg_field(word, 16));
                return Ok(Some(Self::SveContiguousStoreScalar {
                    msize,
                    esize,
                    pg,
                    zt,
                    rn,
                    rm,
                }));
